const entries = $input.all().map(i => i.json);
if (entries.length === 0) {
  return [{ json: { skip: true, count: 0 } }];
}

const summaries = entries.slice(0, 15).map(e =>
  `[${e.type}] ${e.project}: ${e.summary} (score: ${e.social_score})`
).join('\n');

const ids = entries.map(e => e.id);

return [{
  json: {
    skip: false,
    count: entries.length,
    summaries,
    ids,
    prompt: `You are a build-in-public journal assistant for a solopreneur.\nWrite a weekly digest from these journal entries. Include:\n1. **Week summary**: 2-3 sentences on themes, energy, and what the week felt like\n2. **Top 5 moments**: The highest-value entries with a brief note on why each matters for social content\n3. **Suggested narratives**: 2-3 blog/LinkedIn post angles that could be written from this week's entries\n\nEntries (sorted by social-worthiness score, highest first):\n${summaries}\n\nWrite in a warm, authentic voice. This is for the builder to review, not for publishing directly.`
  }
}];

const response = $input.first().json;
const digestContent = response.content?.[0]?.text || 'Failed to generate digest.';
const prepData = $('Prepare Prompt').first().json;

// ISO week
const d = new Date();
d.setHours(0, 0, 0, 0);
d.setDate(d.getDate() + 3 - ((d.getDay() + 6) % 7));
const yearStart = new Date(d.getFullYear(), 0, 4);
const weekNum = 1 + Math.round(((d - yearStart) / 86400000 - 3 + ((yearStart.getDay() + 6) % 7)) / 7);
const week = `${d.getFullYear()}-W${String(weekNum).padStart(2, '0')}`;

return [{
  json: {
    week,
    digestContent,
    count: prepData.count,
    ids: prepData.ids
  }
}];

